import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  // Kiểm tra cameraData
  if (!cameraData) {
    return (
      <div style={{ padding: '40px', textAlign: 'center' }}>
        <p>Không có dữ liệu camera. Vui lòng quay lại.</p>
        <button onClick={onBack}>Quay lại</button>
      </div>
    );
  }

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const [polyPoints, setPolyPoints] = useState([]);
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [showPreview, setShowPreview] = useState(false);
  const [quickComplete, setQuickComplete] = useState(false);

  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  const FIXED_WIDTH = 800;
  const FIXED_HEIGHT = 450;

  // Khởi tạo canvas
  useEffect(() => {
    if (canvasRef.current) {
      canvasRef.current.width = FIXED_WIDTH;
      canvasRef.current.height = FIXED_HEIGHT;
    }
  }, []);

  // Vẽ ảnh lên canvas
  useEffect(() => {
    if (canvasRef.current && cameraData.imagePreview) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
        redrawAll();
      };
    }
  }, [cameraData.imagePreview]);

  // Format output với giá trị 0 cho các bước chưa vẽ
  const generateOutput = () => {
    // Axis: nếu chưa vẽ thì trả về [0,0,0,0]
    const axis = lines[0] ? [
      Number((lines[0][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[0][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[0][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    // Coord: nếu chưa vẽ thì trả về [0,0,0,0]
    const coord = lines[1] ? [
      Number((lines[1][0] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][1] / FIXED_HEIGHT).toFixed(3)),
      Number((lines[1][2] / FIXED_WIDTH).toFixed(3)),
      Number((lines[1][3] / FIXED_HEIGHT).toFixed(3))
    ] : [0, 0, 0, 0];

    // Zone: nếu chưa đủ 4 điểm thì trả về 8 số 0
    const zone = polyPoints.length >= 4 ? 
      polyPoints.slice(0, 4).flatMap(p => [
        Number((p.x / FIXED_WIDTH).toFixed(3)),
        Number((p.y / FIXED_HEIGHT).toFixed(3))
      ]) : [0, 0, 0, 0, 0, 0, 0, 0];

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl || "",
            cam_id: generateUUID()
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [{
              ID: generateUUID(),
              type: 1,
              axis: axis,
              coord: coord
            }],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  // Format output realtime
  const getCurrentOutput = () => {
    const output = generateOutput();
    return {
      ...output,
      _metadata: {
        steps: {
          axis: lines.length >= 1 ? 'completed' : 'pending',
          coord: lines.length >= 2 ? 'completed' : 'pending',
          zone: polyPoints.length >= 4 ? 'completed' : `pending (${polyPoints.length}/4)`
        }
      }
    };
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  // Xử lý mouse events (giữ nguyên)
  const handleMouseDown = (e) => {
    e.preventDefault();
    if (!canvasRef.current) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    if (currentStep === 3) {
      if (polyPoints.length < 4) {
        const newPoint = { x, y };
        setPolyPoints([...polyPoints, newPoint]);
      }
    } else {
      setDrawing(true);
      setIx(x);
      setIy(y);
    }
  };

  const handleMouseMove = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const ctx = canvasRef.current.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (currentStep === 1) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.stroke();
      ctx.setLineDash([]);
    } else if (currentStep === 2) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2, true);
    }
  };

  const handleMouseUp = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const newLine = [ix, iy, x, y];
    setLines([...lines, newLine]);
    setDrawing(false);

    if (currentStep === 1) {
      setCurrentStep(2);
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  };

  // Hàm vẽ
  const drawPoint = (ctx, x, y, number) => {
    ctx.beginPath();
    ctx.arc(x, y, 6, 0, 2 * Math.PI);
    ctx.fillStyle = '#ff4444';
    ctx.fill();
    ctx.strokeStyle = 'white';
    ctx.lineWidth = 2;
    ctx.stroke();

    ctx.fillStyle = 'white';
    ctx.font = 'bold 14px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(number, x, y);
  };

  const drawLine = (ctx, x1, y1, x2, y2, color, width = 2) => {
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width, isPreview = false) => {
    const headLength = isPreview ? 15 : 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    if (isPreview) ctx.setLineDash([5, 5]);
    ctx.stroke();
    if (isPreview) ctx.setLineDash([]);

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const redrawAll = () => {
    if (!canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');

    if (cameraData.imagePreview) {
      const img = new Image();
      img.src = cameraData.imagePreview;
      ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
    }

    if (lines[0]) {
      const [x1, y1, x2, y2] = lines[0];
      drawLine(ctx, x1, y1, x2, y2, '#000000', 3);
    }

    if (lines[1]) {
      const [x1, y1, x2, y2] = lines[1];
      drawArrow(ctx, x1, y1, x2, y2, '#ff0000', 4, false);
    }

    if (polyPoints.length > 0) {
      for (let i = 0; i < polyPoints.length - 1; i++) {
        drawLine(ctx, polyPoints[i].x, polyPoints[i].y, polyPoints[i+1].x, polyPoints[i+1].y, '#ff4444', 2);
      }

      if (polyPoints.length === 4) {
        drawLine(ctx, polyPoints[3].x, polyPoints[3].y, polyPoints[0].x, polyPoints[0].y, '#ff4444', 2);

        ctx.fillStyle = 'rgba(255, 68, 68, 0.1)';
        ctx.beginPath();
        ctx.moveTo(polyPoints[0].x, polyPoints[0].y);
        ctx.lineTo(polyPoints[1].x, polyPoints[1].y);
        ctx.lineTo(polyPoints[2].x, polyPoints[2].y);
        ctx.lineTo(polyPoints[3].x, polyPoints[3].y);
        ctx.closePath();
        ctx.fill();
      }

      polyPoints.forEach((point, index) => {
        drawPoint(ctx, point.x, point.y, index + 1);
      });
    }
  };

  const handleQuickComplete = () => {
    setQuickComplete(true);
    setShowPreview(true);
  };

  const handleSave = () => {
    const output = generateOutput();
    onSave(output.list_camera[0].config);
  };

  const handleReset = () => {
    setLines([]);
    setPolyPoints([]);
    setCurrentStep(1);
    setDrawing(false);
    setShowPreview(false);
    setQuickComplete(false);

    if (canvasRef.current && cameraData.imagePreview) {
      const ctx = canvasRef.current.getContext('2d');
      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
      };
    }
  };

  useEffect(() => {
    redrawAll();
  }, [lines, polyPoints]);

  const currentOutput = getCurrentOutput();
  const isStep1Completed = lines.length >= 1;
  const isStep2Completed = lines.length >= 2;
  const isStep3Completed = polyPoints.length >= 4;

  return (
    <div style={{ padding: '20px' }}>
      {/* Steps với trạng thái realtime */}
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 1 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${isStep1Completed ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>1️⃣</div>
          <strong>Vẽ Axis</strong>
          <div style={{ 
            marginTop: '5px',
            color: isStep1Completed ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {isStep1Completed ? '✅ Hoàn thành' : '⏳ 0'}
          </div>
        </div>

        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 2 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${isStep2Completed ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>2️⃣</div>
          <strong>Vẽ Coord</strong>
          <div style={{ 
            marginTop: '5px',
            color: isStep2Completed ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {isStep2Completed ? '✅ Hoàn thành' : '⏳ 0'}
          </div>
        </div>

        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 3 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${isStep3Completed ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>3️⃣</div>
          <strong>Vẽ Polygon</strong>
          <div style={{ 
            marginTop: '5px',
            color: isStep3Completed ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {isStep3Completed ? '✅ Hoàn thành' : `⏳ ${polyPoints.length}/4`}
          </div>
        </div>
      </div>

      {/* Canvas */}
      <div style={{ marginBottom: '20px' }}>
        <canvas
          ref={canvasRef}
          width={FIXED_WIDTH}
          height={FIXED_HEIGHT}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
          style={{
            width: '100%',
            height: 'auto',
            cursor: currentStep === 3 && polyPoints.length < 4 ? 'crosshair' : 'default',
            border: '2px solid #ddd',
            borderRadius: '8px',
            background: '#f0f0f0'
          }}
        />
      </div>

      {/* Status hiện tại */}
      <div style={{ 
        padding: '15px', 
        background: '#e9ecef', 
        borderRadius: '8px', 
        marginBottom: '20px'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <strong>Bước hiện tại: </strong>
            <span style={{ color: '#007bff' }}>
              {currentStep === 1 && 'Vẽ Axis (line đen)'}
              {currentStep === 2 && 'Vẽ Coord (mũi tên đỏ)'}
              {currentStep === 3 && `Vẽ Polygon (${polyPoints.length}/4 điểm)`}
            </span>
          </div>
          <div>
            <strong>Kết quả: </strong>
            <span>
              Axis: {isStep1Completed ? '✓' : '0'} | 
              Coord: {isStep2Completed ? '✓' : '0'} | 
              Zone: {isStep3Completed ? '✓' : '0'}
            </span>
          </div>
        </div>
      </div>

      {/* Nút hoàn thành nhanh */}
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <button 
          onClick={handleQuickComplete}
          style={{
            flex: 1,
            padding: '15px',
            background: '#17a2b8',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: 'pointer'
          }}
        >
          ⚡ Hoàn thành nhanh (xem kết quả)
        </button>

        <button 
          onClick={() => {
            if (isStep1Completed && isStep2Completed && isStep3Completed) {
              handleSave();
            } else {
              alert('Vui lòng vẽ đủ 3 bước hoặc dùng "Hoàn thành nhanh" để xem kết quả với giá trị 0');
            }
          }}
          style={{
            flex: 1,
            padding: '15px',
            background: isStep1Completed && isStep2Completed && isStep3Completed ? '#28a745' : '#6c757d',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: isStep1Completed && isStep2Completed && isStep3Completed ? 'pointer' : 'not-allowed'
          }}
        >
          💾 Lưu camera
        </button>
      </div>

      {/* Preview realtime */}
      {(showPreview || quickComplete) && (
        <div style={{ 
          background: '#1e1e1e', 
          color: 'white', 
          padding: '15px', 
          borderRadius: '8px', 
          marginBottom: '20px' 
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
            <h4 style={{ margin: 0 }}>📋 Kết quả realtime:</h4>
            <div style={{ fontSize: '12px', color: '#ffc107' }}>
              {!isStep1Completed && '⚠️ Axis = 0 | '}
              {!isStep2Completed && '⚠️ Coord = 0 | '}
              {!isStep3Completed && '⚠️ Zone = 0'}
            </div>
          </div>

          <pre style={{ 
            background: '#2d2d2d', 
            padding: '10px', 
            borderRadius: '4px',
            overflow: 'auto',
            fontSize: '12px',
            maxHeight: '200px'
          }}>
            {JSON.stringify(currentOutput, null, 2)}
          </pre>

          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: '1fr 1fr 1fr', 
            gap: '10px', 
            marginTop: '10px' 
          }}>
            <div style={{ 
              padding: '10px', 
              background: isStep1Completed ? '#28a745' : '#dc3545', 
              borderRadius: '4px',
              textAlign: 'center'
            }}>
              <strong>Axis</strong>
              <div style={{ fontSize: '12px' }}>
                {isStep1Completed ? currentOutput.list_camera[0].config.zone[0].axis.join(', ') : '[0, 0, 0, 0]'}
              </div>
            </div>
            <div style={{ 
              padding: '10px', 
              background: isStep2Completed ? '#28a745' : '#dc3545', 
              borderRadius: '4px',
              textAlign: 'center'
            }}>
              <strong>Coord</strong>
              <div style={{ fontSize: '12px' }}>
                {isStep2Completed ? currentOutput.list_camera[0].config.zone[0].coord.join(', ') : '[0, 0, 0, 0]'}
              </div>
            </div>
            <div style={{ 
              padding: '10px', 
              background: isStep3Completed ? '#28a745' : '#dc3545', 
              borderRadius: '4px',
              textAlign: 'center'
            }}>
              <strong>Zone</strong>
              <div style={{ fontSize: '12px' }}>
                {isStep3Completed ? currentOutput.list_camera[0].config.zone[0].coord.join(', ') : '[0, 0, 0, 0, 0, 0, 0, 0]'}
              </div>
            </div>
          </div>

          <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
            <button 
              onClick={() => {
                navigator.clipboard.writeText(JSON.stringify(currentOutput, null, 2));
                alert('Đã copy JSON!');
              }}
              style={{
                flex: 1,
                padding: '10px',
                background: '#007bff',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              📋 Copy JSON
            </button>
          </div>
        </div>
      )}

      {/* Actions */}
      <div style={{ display: 'flex', gap: '10px' }}>
        <button 
          onClick={onBack}
          style={{
            flex: 1,
            padding: '10px',
            background: '#6c757d',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          ← Quay lại
        </button>
        <button 
          onClick={handleReset}
          style={{
            flex: 1,
            padding: '10px',
            background: '#ffc107',
            color: '#212529',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          ⟲ Vẽ lại
        </button>
      </div>
    </div>
  );
}

export default DrawingCanvas;
